1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width,initial-scale=1.0,user-scalable=no">
6	<title>贪吃蛇</title>
7	<style>
8	*{margin:0;padding:0;box-sizing:border-box}
9	body{background:#1a1a2e;display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;font-family:Arial,sans-serif;color:#e0e0e0;overflow:hidden;touch-action:none}
10	#header{display:flex;gap:30px;margin-bottom:10px;font-size:18px;min-height:28px}
11	#header span{font-weight:bold}
12	.score-val{color:#00d2ff}
13	canvas{border:2px solid #00d2ff;border-radius:4px;display:block;max-width:95vw;max-height:70vh}
14	#info{margin-top:10px;font-size:13px;color:#888;text-align:center;line-height:1.6}
15	#overlay{position:absolute;display:flex;flex-direction:column;align-items:center;justify-content:center;pointer-events:none}
16	#overlay.active{pointer-events:auto}
17	#overlay h2{font-size:28px;margin-bottom:10px;color:#00d2ff}
18	#overlay p{font-size:16px;margin-bottom:16px}
19	#overlay button{padding:10px 28px;font-size:18px;border:2px solid #00d2ff;background:transparent;color:#00d2ff;border-radius:6px;cursor:pointer;transition:all .2s}
20	#overlay button:hover{background:#00d2ff;color:#1a1a2e}
21	</style>
22	</head>
23	<body>
24	<div id="header">
25	  <span>分数: <span id="score" class="score-val">0</span></span>
26	  <span>最高分: <span id="highScore" class="score-val">0</span></span>
27	</div>
28	<canvas id="gameCanvas"></canvas>
29	<div id="overlay" class="active">
30	  <h2 id="overlayTitle">贪吃蛇</h2>
31	  <p id="overlayMsg">按 空格键 或点击按钮开始</p>
32	  <button id="actionBtn">开始游戏</button>
33	</div>
34	<div id="info">方向键 / WASD 控制方向 · 空格键 暂停/恢复 · 移动端滑动控制</div>
35	<script>
36	/* ================================================================
37	 * 贪吃蛇 (Snake Game) — 单文件 HTML5 Canvas 实现
38	 * Task ID: task-20260408222240-8c9a8c
39	 * 满足需求: F001-F014, NFR001-NFR005
40	 * ================================================================ */
41	'use strict';
42	
43	// ─── 常量配置 (RenderConfig / SpeedConfig 来自 data_model) ───
44	const GRID     = 20;          // F001: 20×20 网格
45	const INIT_LEN = 3;           // F002: 初始蛇长度 3
46	const BASE_INTERVAL = 150;    // F003/F013: 初始帧间隔 150ms
47	const MIN_INTERVAL  = 50;     // F013: 最小帧间隔 50ms
48	const SPEED_STEP    = 10;     // F013: 每级减少 10ms
49	const FOOD_PER_LEVEL = 5;     // F013: 每 5 个食物加速一次
50	const SCORE_PER_FOOD = 10;    // F010: 每个食物 10 分
51	const SWIPE_THRESHOLD = 30;   // F005: 触屏滑动最小阈值 30px
52	const LS_KEY = 'snakeHighScore'; // F011/NFR005: localStorage 键
53	
54	// ─── 方向枚举 (Direction 实体) ───
55	const DIR = { UP:{x:0,y:-1}, DOWN:{x:0,y:1}, LEFT:{x:-1,y:0}, RIGHT:{x:1,y:0} };
56	
57	// ─── 颜色配置 (WCAG AA ≥4.5:1 对比度 — NFR003) ───
58	const COLOR = {
59	  bg:       '#0f3460',   // 画布背景
60	  grid:     '#16213e',   // 网格线
61	  head:     '#00d2ff',   // 蛇头 — F002
62	  body:     '#0a8f6a',   // 蛇身 — F002
63	  food:     '#e94560',   // 食物红色 — F006
64	  overlay:  'rgba(0,0,0,0.7)'
65	};
66	
67	// ─── 游戏状态机 (StateManager — F012) ───
68	// IDLE → PLAYING → PAUSED → GAME_OVER
69	const STATE = { IDLE:'IDLE', PLAYING:'PLAYING', PAUSED:'PAUSED', GAME_OVER:'GAME_OVER' };
70	
71	// ─── DOM 引用 ───
72	const canvas     = document.getElementById('gameCanvas');
73	const ctx        = canvas.getContext('2d');
74	const scoreEl    = document.getElementById('score');
75	const highScoreEl= document.getElementById('highScore');
76	const overlay    = document.getElementById('overlay');
77	const overlayTitle = document.getElementById('overlayTitle');
78	const overlayMsg = document.getElementById('overlayMsg');
79	const actionBtn  = document.getElementById('actionBtn');
80	
81	// ─── 游戏运行时状态 (GameState 实体) ───
82	let state, snake, food, direction, nextDirection, score, highScore;
83	let foodEaten, interval, lastTime, accumulator, animId;
84	let directionChanged; // F004: 每帧只响应第一次有效方向变更
85	let audioCtx;         // F014: Web Audio API 上下文 (懒初始化)
86	
87	// ─── Canvas 尺寸自适应 (F001/NFR002) ───
88	let cellSize;
89	function resizeCanvas() {
90	  const maxW = Math.min(window.innerWidth * 0.95, 600);
91	  const maxH = Math.min(window.innerHeight * 0.7, 600);
92	  const size = Math.floor(Math.min(maxW, maxH) / GRID) * GRID;
93	  canvas.width  = size;
94	  canvas.height = size;
95	  cellSize = size / GRID;
96	  // 定位 overlay
97	  const rect = canvas.getBoundingClientRect();
98	  overlay.style.width  = rect.width + 'px';
99	  overlay.style.height = rect.height + 'px';
100	  overlay.style.left   = rect.left + 'px';
101	  overlay.style.top    = rect.top + 'px';
102	  if (state) render(); // 重绘当前帧
103	}
104	window.addEventListener('resize', resizeCanvas);
105	
106	// ─── 高分读写 (F011/NFR005) ───
107	function loadHighScore() {
108	  try { return parseInt(localStorage.getItem(LS_KEY), 10) || 0; } catch { return 0; }
109	}
110	function saveHighScore(val) {
111	  try { localStorage.setItem(LS_KEY, String(val)); } catch { /* 静默 */ }
112	}
113	
114	// ─── 初始化游戏 (F002/F006/F010/F012) ───
115	function initGame() {
116	  state     = STATE.IDLE;
117	  score     = 0;
118	  foodEaten = 0;
119	  interval  = BASE_INTERVAL;
120	  direction = DIR.RIGHT;          // F002: 默认朝右
121	  nextDirection = DIR.RIGHT;
122	  directionChanged = false;
123	  accumulator = 0;
124	  lastTime = 0;
125	  // F002: 蛇在画布中央, 长度 3
126	  const startX = Math.floor(GRID / 2);
127	  const startY = Math.floor(GRID / 2);
128	  snake = [];
129	  for (let i = 0; i < INIT_LEN; i++) snake.push({ x: startX - i, y: startY });
130	  spawnFood();                    // F006: 初始食物
131	  highScore = loadHighScore();
132	  scoreEl.textContent    = '0';
133	  highScoreEl.textContent = String(highScore);
134	  showOverlay('贪吃蛇', '按 空格键 或点击按钮开始', '开始游戏');
135	}
136	
137	// ─── 食物生成 (F006) — 随机空闲格子 ───
138	function spawnFood() {
139	  const occupied = new Set(snake.map(s => s.x + ',' + s.y));
140	  const free = [];
141	  for (let x = 0; x < GRID; x++)
142	    for (let y = 0; y < GRID; y++)
143	      if (!occupied.has(x + ',' + y)) free.push({ x, y });
144	  if (free.length === 0) return; // 网格占满 — 极端情况
145	  food = free[Math.floor(Math.random() * free.length)];
146	}
147	
148	// ─── 蛇移动 + 碰撞检测 (F003/F007/F008/F009) ───
149	function update() {
150	  direction = nextDirection;
151	  directionChanged = false;
152	  const head = { x: snake[0].x + direction.x, y: snake[0].y + direction.y };
153	
154	  // F008: 撞墙检测
155	  if (head.x < 0 || head.x >= GRID || head.y < 0 || head.y >= GRID) {
156	    gameOver(); return;
157	  }
158	  // F009: 撞自身检测
159	  for (let i = 0; i < snake.length; i++) {
160	    if (snake[i].x === head.x && snake[i].y === head.y) { gameOver(); return; }
161	  }
162	  snake.unshift(head);
163	
164	  // F007: 吃食物判定
165	  if (head.x === food.x && head.y === food.y) {
166	    score += SCORE_PER_FOOD;          // F010
167	    foodEaten++;
168	    scoreEl.textContent = String(score);
169	    playSound('eat');                  // F014
170	    spawnFood();                       // F006
171	    // F013: 速度递增 — 每 5 个食物减 10ms, 下限 50ms
172	    if (foodEaten % FOOD_PER_LEVEL === 0 && interval > MIN_INTERVAL) {
173	      interval = Math.max(MIN_INTERVAL, interval - SPEED_STEP);
174	    }
175	  } else {
176	    snake.pop(); // 未吃到食物, 移除尾部
177	  }
178	}
179	
180	// ─── 游戏结束 (F008/F009/F011/F012) ───
181	function gameOver() {
182	  state = STATE.GAME_OVER;
183	  playSound('die');                    // F014
184	  if (score > highScore) {             // F011
185	    highScore = score;
186	    saveHighScore(highScore);
187	    highScoreEl.textContent = String(highScore);
188	  }
189	  cancelAnimationFrame(animId);
190	  showOverlay('游戏结束', '得分: ' + score, '重新开始');
191	}
192	
193	// ─── 渲染 (Renderer — F001/F002/F006) ───
194	function render() {
195	  const cs = cellSize;
196	  // 清除画布 + 绘制背景
197	  ctx.fillStyle = COLOR.bg;
198	  ctx.fillRect(0, 0, canvas.width, canvas.height);
199	  // 网格线
200	  ctx.strokeStyle = COLOR.grid;
201	  ctx.lineWidth = 0.5;
202	  for (let i = 0; i <= GRID; i++) {
203	    ctx.beginPath(); ctx.moveTo(i * cs, 0); ctx.lineTo(i * cs, canvas.height); ctx.stroke();
204	    ctx.beginPath(); ctx.moveTo(0, i * cs); ctx.lineTo(canvas.width, i * cs); ctx.stroke();
205	  }
206	  // 食物 — 红色圆形 (F006)
207	  ctx.fillStyle = COLOR.food;
208	  ctx.beginPath();
209	  ctx.arc(food.x * cs + cs / 2, food.y * cs + cs / 2, cs * 0.4, 0, Math.PI * 2);
210	  ctx.fill();
211	  // 蛇身 (F002)
212	  for (let i = snake.length - 1; i >= 0; i--) {
213	    ctx.fillStyle = i === 0 ? COLOR.head : COLOR.body;
214	    ctx.fillRect(snake[i].x * cs + 1, snake[i].y * cs + 1, cs - 2, cs - 2);
215	    if (i === 0) { // 蛇头眼睛装饰
216	      ctx.fillStyle = '#fff';
217	      const ex = snake[0].x * cs + cs * 0.3;
218	      const ey = snake[0].y * cs + cs * 0.3;
219	      ctx.fillRect(ex, ey, cs * 0.15, cs * 0.15);
220	      ctx.fillRect(ex + cs * 0.3, ey, cs * 0.15, cs * 0.15);
221	    }
222	  }
223	}
224	
225	// ─── 主循环 (GameLoop — requestAnimationFrame + 累加器) ───
226	function gameLoop(timestamp) {
227	  if (state !== STATE.PLAYING) return;
228	  if (!lastTime) lastTime = timestamp;
229	  accumulator += timestamp - lastTime;
230	  lastTime = timestamp;
231	  // 以固定间隔步进游戏逻辑 (NFR001: 逻辑 ≤1ms)
232	  while (accumulator >= interval) {
233	    update();
234	    accumulator -= interval;
235	    if (state !== STATE.PLAYING) return; // update 可能触发 gameOver
236	  }
237	  render();
238	  animId = requestAnimationFrame(gameLoop);
239	}
240	
241	// ─── 开始/重启游戏 ───
242	function startGame() {
243	  initGame();
244	  state = STATE.PLAYING;
245	  hideOverlay();
246	  lastTime = 0;
247	  accumulator = 0;
248	  render();
249	  animId = requestAnimationFrame(gameLoop);
250	}
251	
252	// ─── Overlay 管理 (F012) ───
253	function showOverlay(title, msg, btnText) {
254	  overlayTitle.textContent = title;
255	  overlayMsg.textContent   = msg;
256	  actionBtn.textContent    = btnText;
257	  overlay.classList.add('active');
258	}
259	function hideOverlay() { overlay.classList.remove('active'); }
260	
261	// ─── 输入处理 (InputHandler — F004/F005/F012) ───
262	
263	/** F004: 键盘控制 — 方向键 & WASD; 禁止180°反向; 每帧仅首次有效 */
264	const KEY_MAP = {
265	  ArrowUp:'UP', ArrowDown:'DOWN', ArrowLeft:'LEFT', ArrowRight:'RIGHT',
266	  w:'UP', W:'UP', s:'DOWN', S:'DOWN', a:'LEFT', A:'LEFT', d:'RIGHT', D:'RIGHT'
267	};
268	const OPPOSITE = { UP:'DOWN', DOWN:'UP', LEFT:'RIGHT', RIGHT:'LEFT' };
269	const DIR_NAME = { UP:DIR.UP, DOWN:DIR.DOWN, LEFT:DIR.LEFT, RIGHT:DIR.RIGHT };
270	
271	// 获取当前方向名称辅助函数
272	function getDirName(d) {
273	  if (d === DIR.UP) return 'UP';
274	  if (d === DIR.DOWN) return 'DOWN';
275	  if (d === DIR.LEFT) return 'LEFT';
276	  return 'RIGHT';
277	}
278	
279	document.addEventListener('keydown', function(e) {
280	  // F012: 空格键 — 开始/暂停/恢复
281	  if (e.key === ' ' || e.code === 'Space') {
282	    e.preventDefault();
283	    handleAction();
284	    return;
285	  }
286	  if (state !== STATE.PLAYING) return;
287	  const dirKey = KEY_MAP[e.key];
288	  if (!dirKey) return;
289	  e.preventDefault();
290	  // F004: 禁止 180° 反向
291	  const curName = getDirName(direction);
292	  if (dirKey === OPPOSITE[curName]) return;
293	  // F004: 每帧只响应首次方向变更
294	  if (directionChanged) return;
295	  nextDirection = DIR_NAME[dirKey];
296	  directionChanged = true;
297	});
298	
299	/** F012: 统一动作处理 (按钮点击 / 空格键) */
300	function handleAction() {
301	  if (state === STATE.IDLE || state === STATE.GAME_OVER) {
302	    startGame();
303	  } else if (state === STATE.PLAYING) {
304	    state = STATE.PAUSED;
305	    cancelAnimationFrame(animId);
306	    showOverlay('已暂停', '按 空格键 或点击按钮恢复', '继续游戏');
307	  } else if (state === STATE.PAUSED) {
308	    state = STATE.PLAYING;
309	    hideOverlay();
310	    lastTime = 0;
311	    accumulator = 0;
312	    animId = requestAnimationFrame(gameLoop);
313	  }
314	}
315	actionBtn.addEventListener('click', handleAction);
316	
317	/** F005: 触屏滑动控制 */
318	let touchStartX = 0, touchStartY = 0;
319	canvas.addEventListener('touchstart', function(e) {
320	  const t = e.touches[0];
321	  touchStartX = t.clientX;
322	  touchStartY = t.clientY;
323	}, { passive: true });
324	
325	canvas.addEventListener('touchend', function(e) {
326	  if (state !== STATE.PLAYING) {
327	    handleAction(); return;
328	  }
329	  const t = e.changedTouches[0];
330	  const dx = t.clientX - touchStartX;
331	  const dy = t.clientY - touchStartY;
332	  const absDx = Math.abs(dx), absDy = Math.abs(dy);
333	  // F005: 滑动距离 < 30px 不触发
334	  if (Math.max(absDx, absDy) < SWIPE_THRESHOLD) return;
335	  let dirKey;
336	  if (absDx > absDy) dirKey = dx > 0 ? 'RIGHT' : 'LEFT';
337	  else dirKey = dy > 0 ? 'DOWN' : 'UP';
338	  const curName = getDirName(direction);
339	  if (dirKey === OPPOSITE[curName]) return;
340	  if (directionChanged) return;
341	  nextDirection = DIR_NAME[dirKey];
342	  directionChanged = true;
343	}, { passive: true });
344	
345	// ─── 音效 (AudioManager — F014) — Web Audio API, 懒初始化 ───
346	function initAudio() {
347	  try {
348	    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
349	  } catch { audioCtx = null; }
350	}
351	
352	/**
353	 * F014: 播放简短音效 — 吃食物(eat)≤200ms, 游戏结束(die)≤500ms
354	 * 使用 OscillatorNode 合成, 无需外部音频文件
355	 */
356	function playSound(type) {
357	  if (!audioCtx) initAudio();
358	  if (!audioCtx) return; // 不支持则静默跳过 (F014 AC)
359	  try {
360	    const osc  = audioCtx.createOscillator();
361	    const gain = audioCtx.createGain();
362	    osc.connect(gain);
363	    gain.connect(audioCtx.destination);
364	    const now = audioCtx.currentTime;
365	    if (type === 'eat') {
366	      osc.frequency.setValueAtTime(600, now);
367	      osc.frequency.linearRampToValueAtTime(900, now + 0.1);
368	      gain.gain.setValueAtTime(0.15, now);
369	      gain.gain.linearRampToValueAtTime(0, now + 0.15);
370	      osc.start(now); osc.stop(now + 0.2);
371	    } else {
372	      osc.frequency.setValueAtTime(300, now);
373	      osc.frequency.linearRampToValueAtTime(100, now + 0.4);
374	      gain.gain.setValueAtTime(0.2, now);
375	      gain.gain.linearRampToValueAtTime(0, now + 0.45);
376	      osc.start(now); osc.stop(now + 0.5);
377	    }
378	  } catch { /* 静默跳过 */ }
379	}
380	
381	// ─── 启动 ───
382	resizeCanvas();
383	initGame();
384	render();
385	</script>
386	</body>
387	</html>
